import sys
class TrieNode:
    def __init__(self):
        self.is_word = False
        self.children = [None]*26

class Solution:
    def insert(self, word):
        root = TrieNode()
        for i in range(len(word)):
            c = word[i]
            if not root.children[ord(c)-ord('a')]: root.children[ord(c)-ord('a')] = TrieNode()
            root = root.children[ord(c)-ord('a')]
        root.is_word = True
        return True

