#include <iostream>
#include <vector>
#include <string>
using namespace std;

struct TrieNode {
    bool isWord;
    vector<TrieNode*> children;
    TrieNode() { children.resize(26, nullptr); }
};

class Solution {
public:
    bool insert(string word, TrieNode* root) {
        TrieNode* current = root;
        for (char c : word) {
            if (current->children[c - 'a'] == nullptr) current->children[c - 'a'] = new TrieNode();
            current = current->children[c - 'a'];
        }
        return current->isWord = true;
    }
};

int main() {
    string input;
    getline(cin, input);
    Solution solution;
    size_t pos = 0;
    while ((pos = input.find(' ')) != string::npos) {
        string word = input.substr(0, pos);
        input.erase(0, pos + 1);
        cout << (solution.insert(word) ? 'True' : 'False') << '\n';
    }
    string lastWord = input;
    cout << (solution.insert(lastWord) ? 'True' : 'False') << '\n';
    return 0;
}
